    const [batch, setBatch] = useState('');
    const [isBatchMissing, setIsBatchMissing] = useState(false);
    const [quantity, setQuantity] = useState('');
    const [lastSaved, setLastSaved] = useState<number | null>(null);
    const [scannedItems, setScannedItems] = useState<ScannedItem[]>([]);

    const [confirmModal, setConfirmModal] = useState<{
        isOpen: boolean;
        title: string;
        message: React.ReactNode;
        onConfirm: () => void;
        type: 'danger' | 'warning';
    }>({
        isOpen: false,
        title: '',
        message: '',
        onConfirm: () => {},
        type: 'danger'
    });

    const activeInventoryTask = useMemo(() => {
        return tasks.find(t => 
            t.partNumber === "Počítanie zásob" && 
            !t.isDone && 
            t.inProgressBy === currentUser
        );
    }, [tasks, currentUser]);

    useEffect(() => {
        const saved = localStorage.getItem('inventory_scans');
        if (saved) {
            try {
                const parsed = JSON.parse(saved);
                setScannedItems(parsed);
                if (parsed.length > 0) setLastSaved(parsed[0].timestamp);
            } catch (e) {
                console.error("Failed to parse inventory scans", e);
            }
        }
    }, []);

    useEffect(() => {
        if (scannedItems.length > 0) {
            localStorage.setItem('inventory_scans', JSON.stringify(scannedItems));
            setLastSaved(Date.now());
        }
    }, [scannedItems]);

    const handleStartInventory = () => {
        onAddTask("Počítanie zásob", "Inventúra", "0", "pallet", "NORMAL", true);
    };

    const handleAddItem = () => {
        const isLocEmpty = !location.trim();
        const isPartEmpty = !partNumber.trim();
        const isQtyEmpty = !quantity.trim();
        const isBatchRequiredAndEmpty = !isBatchMissing && !batch.trim();

        if (isLocEmpty || isPartEmpty || isQtyEmpty || isBatchRequiredAndEmpty) {
            const missingFields = [];
            if (isLocEmpty) missingFields.push(language === 'sk' ? "Lokácia" : "Location");
            if (isPartEmpty) missingFields.push(language === 'sk' ? "Diel" : "Part");
            if (isBatchRequiredAndEmpty) missingFields.push("Batch");
            if (isQtyEmpty) missingFields.push(language === 'sk' ? "Množstvo" : "Quantity");

            const errorMsg = language === 'sk' 
                ? `Prosím, vyplňte povinné polia: ${missingFields.join(', ')}.` 
                : `Please fill required fields: ${missingFields.join(', ')}.`;

            alert(errorMsg);
            return;
        }

        const newItem: ScannedItem = {
            id: crypto.randomUUID(),
            location,
            partNumber,
            batch: isBatchMissing ? '[CHÝBA ŠTÍTOK]' : batch,
            quantity,
            timestamp: Date.now(),
            worker: currentUser
        };
        setScannedItems([newItem, ...scannedItems]);

        setLocation(''); 
        setPartNumber(''); 
        setBatch(''); 
        setIsBatchMissing(false);
        setQuantity('');
        setTimeout(() => locationRef.current?.focus(), 10);
    };

    const handleDeleteItem = (id: string) => {
        setConfirmModal({
            isOpen: true,
            title: language === 'sk' ? "Vymazať položku?" : "Delete item?",
            message: language === 'sk' ? "Naozaj chcete vymazať túto naskenovanú položku?" : "Are you sure you want to delete this scanned item?",
            type: 'danger',
            onConfirm: () => {
                const updated = scannedItems.filter(item => item.id !== id);
                setScannedItems(updated);
                if (updated.length === 0) {
                    localStorage.removeItem('inventory_scans');
                }
                setConfirmModal(prev => ({ ...prev, isOpen: false }));
            }
        });
    };

    const handleClearAll = () => {
        setConfirmModal({
            isOpen: true,
            title: language === 'sk' ? "Vymazať všetko?" : "Clear all?",
            message: language === 'sk' ? "Naozaj chcete vymazať celý zoznam naskenovaných položiek? Táto akcia je nevratná." : "Are you sure you want to clear the entire list? This action cannot be undone.",
            type: 'danger',
            onConfirm: () => {
                setScannedItems([]);
                localStorage.removeItem('inventory_scans');
                setLastSaved(null);
                setConfirmModal(prev => ({ ...prev, isOpen: false }));
            }
        });
    };

    const handleCancelInventory = () => {
        setConfirmModal({
            isOpen: true,
            title: language === 'sk' ? "Zrušiť reláciu inventúry?" : "Cancel inventory session?",
            message: (
                <div className="space-y-4">
                    <p className="font-bold text-red-500">
                        {language === 'sk' 
                            ? "Pozor! Táto akcia vymaže všetky naskenované dáta a ukončí inventúru bez uloženia do systému." 
                            : "Warning! This action will delete all scanned data and end the inventory without saving to the system."}
                    </p>
                    <div className="bg-gray-700/50 p-4 rounded-lg border border-gray-600 text-sm">
                        <p className="text-gray-300">
                            {language === 'sk'
                                ? "Ak chcete dáta uložiť a vygenerovať report, použite zelené tlačidlo"
                                : "If you want to save data and generate a report, use the green button"}
                            <span className="text-green-400 font-black ml-1">"EXPORT & UKONČIŤ"</span>.
                        </p>
                    </div>
                </div>
            ),
            type: 'danger',
            onConfirm: () => {
                if (activeInventoryTask) {
                    onDeleteTask(activeInventoryTask.id);
                }
                setScannedItems([]);
                localStorage.removeItem('inventory_scans');
                setLastSaved(null);
                setConfirmModal(prev => ({ ...prev, isOpen: false }));
            }
        });
    };

    const handleExportAndFinish = () => {
        if (scannedItems.length === 0) {
            alert(language === 'sk' ? "Zoznam je prázdny." : "List is empty.");
            return;
        }

        handleExport();

        const finalCount = scannedItems.length.toString();

        if (activeInventoryTask) {
            onUpdateTask(activeInventoryTask.id, { 
                isDone: true, 
                status: 'completed', 
                completionTime: new Date().toLocaleTimeString('sk-SK'),
                completedBy: currentUser,
                completedAt: Date.now(),
                isInProgress: false,
                inProgressBy: null,
                quantity: finalCount
            });
        }

        setScannedItems([]);
        localStorage.removeItem('inventory_scans');
        setLastSaved(null);
    };

    const handleExport = () => {
        if (scannedItems.length === 0) return;
        if (typeof XLSX === 'undefined') { alert("Library Error"); return; }
        const data = scannedItems.map(item => ({
            "Dátum inventúry": new Date(item.timestamp).toLocaleDateString('sk-SK'),
            "Užívateľ": item.worker,
            "Lokácia": item.location,
            "Číslo dielu": item.partNumber,
            "Batch": item.batch,
            "Množstvo": item.quantity,
            "Presný čas": new Date(item.timestamp).toLocaleTimeString('sk-SK')
        }));
        const ws = XLSX.utils.json_to_sheet(data);
        const wb = XLSX.utils.book_new();
        XLSX.utils.book_append_sheet(wb, ws, "Inventúra");
        XLSX.writeFile(wb, `Inventura_${new Date().toISOString().slice(0, 10)}.xlsx`);
    };

    const toggleBatchMissing = () => {
        const newState = !isBatchMissing;
        setIsBatchMissing(newState);
        if (newState) {
            setBatch('[CHÝBA ŠTÍTOK]');
            setTimeout(() => quantityRef.current?.focus(), 10);
        } else {
            setBatch('');
            setTimeout(() => batchRef.current?.focus(), 10);
        }
    };

    const inputBaseClass = "w-full h-12 bg-gray-700 border border-gray-600 rounded-lg px-4 text-white text-base placeholder-gray-400 focus:outline-none focus:ring-2 focus:ring-[#4169E1] transition-all font-mono uppercase";
    const dangerButtonClass = "bg-red-900/40 hover:bg-red-800 text-red-100 px-6 py-5 rounded-xl text-base font-black border-2 border-red-800/50 shadow-lg transition-all active:scale-95 uppercase tracking-wider flex items-center justify-center gap-2";

    return (
        <div className="max-w-4xl mx-auto space-y-8 pb-20 animate-fade-in">
            <div className="bg-gray-800 p-6 sm:p-8 rounded-xl shadow-lg border border-gray-700 relative overflow-hidden">
                {!activeInventoryTask ? (
                    <div className="flex flex-col items-center justify-center py-12 space-y-8">
                        <div className="text-center">
                            <h2 className="text-3xl font-bold text-white uppercase tracking-widest">{language === 'sk' ? 'Inventúra nie je spustená' : 'Inventory not started'}</h2>
                            <p className="text-gray-400 text-base mt-3">{language === 'sk' ? 'Kliknutím začnete reláciu počítania.' : 'Click to start a counting session.'}</p>
                        </div>
                        <button 
                            onClick={handleStartInventory}
                            className="bg-[#4169E1] hover:bg-[#3151b1] text-white font-black py-8 px-16 rounded-2xl shadow-[0_0_25px_rgba(65,105,225,0.4)] transition-all active:scale-95 uppercase tracking-[0.25em] text-2xl border-2 border-[#5a81f3]"
                        >
                            📋 {language === 'sk' ? 'Spustiť Inventúru' : 'Start Inventory'}
                        </button>
                    </div>
                ) : (
                    <>
                        <div className="flex justify-between items-start sm:items-center mb-10 border-b border-gray-700 pb-6">
                            <div>
                                <h1 className="text-4xl font-extrabold text-[#4169E1] uppercase tracking-widest leading-none">
                                    {t('tab_inventory')}
                                </h1>
                                <div className="flex gap-6 items-center mt-3">
                                    <span className="bg-[#4169E1]/20 text-[#4169E1] text-xs font-black px-3 py-1 rounded-md border border-[#4169E1]/40 animate-pulse uppercase">Aktívna relácia</span>
                                    <p className="text-xs text-gray-500 uppercase font-mono">
                                        Položiek: <span className="text-white font-bold">{scannedItems.length}</span>
                                    </p>
                                </div>
                            </div>

                            <button 
                                onClick={handleCancelInventory}
                                className={dangerButtonClass.replace('px-6 py-5', 'px-5 py-3 text-xs')}
                            >
                                🛑 {language === 'sk' ? 'Zrušiť reláciu' : 'Cancel session'}
                            </button>
                        </div>

                        <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                            <div>
                                <label className="block text-gray-300 text-base font-bold mb-2 uppercase tracking-wide">Skladová Lokácia</label>
                                <input 
                                    ref={locationRef}
                                    type="text"
                                    value={location}
                                    onChange={(e) => setLocation(e.target.value.toUpperCase())}
                                    onKeyDown={(e) => e.key === 'Enter' && partRef.current?.focus()}
                                    placeholder="NAPR. MA123"
                                    className={inputBaseClass}
                                />
                            </div>
                            <div>
                                <label className="block text-gray-300 text-base font-bold mb-2 uppercase tracking-wide">Číslo dielu</label>
                                <PartNumberInput 
                                    inputRef={partRef}
                                    parts={parts}
                                    onPartSelect={(p) => setPartNumber(p || '')}
                                    onInputChange={(val) => setPartNumber(val.toUpperCase())}
                                    onKeyDown={(e) => e.key === 'Enter' && batchRef.current?.focus()}
                                    placeholder={t('part_placeholder')}
                                    value={partNumber}
                                    onRequestPart={onRequestPart}
                                />
                            </div>
                            <div>
                                <label className="block text-gray-300 text-base font-bold mb-2 uppercase tracking-wide">Batch / Číslo várky</label>
                                <div className="flex gap-3">
                                    <input 
                                        ref={batchRef}
                                        type="text"
                                        readOnly={isBatchMissing}
                                        value={batch}
                                        onChange={(e) => !isBatchMissing && setBatch(e.target.value.toUpperCase())}
                                        onKeyDown={(e) => e.key === 'Enter' && quantityRef.current?.focus()}
                                        placeholder={isBatchMissing ? '' : "489523"}
                                        className={`${inputBaseClass.replace('w-full', 'w-1/2')} ${isBatchMissing ? 'text-red-500 border-red-900/50 bg-red-900/10' : ''}`}
                                    />
                                    <button 
                                        type="button"
                                        onClick={toggleBatchMissing}
                                        className={`w-1/2 h-12 rounded-lg border-2 font-black uppercase text-xs text-white transition-all flex items-center justify-center gap-2 ${isBatchMissing ? 'bg-red-600 border-red-500 shadow-lg' : 'bg-[#4169E1]/20 border-[#4169E1] hover:bg-[#4169E1]/40'}`}
                                    >
                                        🏷️ {language === 'sk' ? 'Chýba štítok' : 'Label missing'}
                                    </button>
                                </div>
                            </div>
                            <div>
                                <label className="block text-gray-300 text-base font-bold mb-2 uppercase tracking-wide">Množstvo</label>
                                <input 
                                    ref={quantityRef}
                                    type="text"
                                    inputMode="decimal"
                                    value={quantity}
                                    onChange={(e) => setQuantity(e.target.value.replace(/[^0-9.,]/g, '').slice(0, 7))}
                                    maxLength={7}
                                    onKeyDown={(e) => e.key === 'Enter' && handleAddItem()}
                                    placeholder="0"
                                    className={`${inputBaseClass} font-black text-lg`}
                                />
                            </div>
                        </div>

                        <button 
                            onClick={handleAddItem}
                            className="w-full mt-10 bg-[#4169E1] hover:bg-[#3151b1] text-white font-black py-6 rounded-2xl shadow-xl transition-all active:scale-95 uppercase tracking-widest text-xl border-2 border-[#5a81f3]"
                        >
                            Pridať do zoznamu
                        </button>
                    </>
                )}
            </div>

            {activeInventoryTask && (
                <div className="bg-gray-800 rounded-xl shadow-lg border border-gray-700 overflow-hidden">
                    <div className="p-5 sm:p-8 border-b border-gray-700 bg-gray-900/50 flex flex-col sm:row justify-between items-center gap-8">
                        <div className="flex items-center gap-6">
                            <h3 className="text-gray-400 font-black uppercase text-base tracking-[0.2em] leading-none">
                                {language === 'sk' ? 'SÚPIS POLOŽIEK' : 'ITEM INVENTORY'}
                            </h3>
                            <span className="bg-[#4169E1]/20 text-white border-2 border-[#4169E1] text-2xl px-5 py-2 rounded-xl font-black font-mono leading-none shadow-lg">
                                {scannedItems.length}
                            </span>
                        </div>
                        <div className="flex flex-wrap w-full sm:w-auto gap-4">
                            <button 
                                onClick={handleClearAll} 
                                className={dangerButtonClass}
                            >
                                {language === 'sk' ? 'Zmazať všetko' : 'Clear all'}
                            </button>
                            <button 
                                onClick={handleExportAndFinish}
                                className="flex-1 sm:flex-none bg-green-700 hover:bg-green-600 text-white px-10 py-5 rounded-xl text-lg font-black shadow-xl transition-all active:scale-95 flex items-center justify-center gap-3 border-2 border-green-500 uppercase tracking-widest"
                            >
                                <svg xmlns="http://www.w3.org/2000/svg" className="h-8 w-8" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-4l-4 4m0 0l-4-4m4 4V4" />
                                </svg>
                                EXPORT & UKONČIŤ
                            </button>
                        </div>
                    </div>

                    <div className="overflow-x-auto custom-scrollbar">
                        <table className="w-full text-left text-base border-collapse">
                            <thead className="bg-gray-900/30 text-gray-500 text-xs font-black uppercase tracking-widest border-b border-gray-700">
                                <tr>
                                    <th className="py-5 px-6">Čas</th>
                                    <th className="py-5 px-6">Lokácia</th>
                                    <th className="py-5 px-6">Číslo dielu</th>
                                    <th className="py-5 px-6">Batch</th>
                                    <th className="py-5 px-6 text-right">Počet (ks)</th>
                                    <th className="py-5 px-6 text-center"></th>
                                </tr>
                            </thead>
                            <tbody className="divide-y divide-gray-700/50">
                                {scannedItems.length > 0 ? (
                                    scannedItems.map(item => (
                                        <tr key={item.id} className="text-gray-300 hover:bg-gray-700/30 transition-colors group">
                                            <td className="py-5 px-6 text-xs text-gray-500 font-mono whitespace-nowrap">{new Date(item.timestamp).toLocaleTimeString('sk-SK')}</td>
                                            <td className="py-5 px-6 font-mono font-bold text-[#4169E1] text-lg">{item.location}</td>
                                            <td className="py-5 px-6 font-mono text-white text-base">{item.partNumber}</td>
                                            <td className={`py-5 px-6 font-mono text-base ${item.batch === '[CHÝBA ŠTÍTOK]' ? 'text-red-500 font-bold' : 'text-gray-500'}`}>
                                                {item.batch || '-'}
                                            </td>
                                            <td className="py-5 px-6 font-black text-white text-right font-mono text-xl">{item.quantity}</td>
                                            <td className="py-5 px-6 text-center w-24">
                                                <button 
                                                    onClick={() => handleDeleteItem(item.id)} 
                                                    className="w-16 h-16 flex items-center justify-center rounded-lg bg-red-900/30 text-red-500 hover:bg-red-800 hover:text-white border border-red-800/50 transition-all active:scale-90"
                                                >
                                                    <TrashIcon className="w-8 h-8" />
                                                </button>
                                            </td>
                                        </tr>
                                    ))
                                ) : (
                                    <tr><td colSpan={6} className="py-16 text-center text-gray-600 italic font-bold text-lg">Zoznam je prázdny. Začnite pridávať položky.</td></tr>
                                )}
                            </tbody>
                        </table>
                    </div>
                </div>
            )}
        </div>
    );
};

export default InventoryTab;

import React, { useState, useMemo } from 'react';
import PartNumberInput from '../PartNumberInput';
import { DBItem, BOMItem, PriorityLevel } from '../../App';

interface BOMScreenProps {
  parts: DBItem[];
  workplaces: DBItem[];
  bomItems: BOMItem[];
  onAddTask: (partNumber: string, workplace: string | null, quantity: string | null, quantityUnit: string | null, priority: PriorityLevel, isLogistics?: boolean) => void;
  onRequestBOM: (parent: string) => Promise<boolean>;
  t: (key: any, params?: any) => string;
  language: string;
}

const ClipboardListIcon: React.FC<{ className?: string }> = ({ className }) => (
    <svg xmlns="http://www.w3.org/2000/svg" className={className} fill="none" viewBox="0 0 24 24" stroke="currentColor">
        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 5H7a2 2 0 00-2 2v12a2 2 0 002 2h10a2 2 0 002-2V7a2 2 0 00-2-2h-2M9 5a2 2 0 002 2h2a2 2 0 002-2M9 5a2 2 0 012-2h2a2 2 0 012 2m-3 7h3m-3 4h3m-6-4h.01M9 16h.01" />
    </svg>
);

const ActivityIcon: React.FC<{ className?: string }> = ({ className }) => (
    <svg xmlns="http://www.w3.org/2000/svg" className={className} fill="none" viewBox="0 0 24 24" stroke="currentColor">
        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M13 10V3L4 14h7v7l9-11h-7z" />
    </svg>
);

const SearchIcon: React.FC<{ className?: string }> = ({ className }) => (
    <svg xmlns="http://www.w3.org/2000/svg" className={className} viewBox="0 0 20 20" fill="currentColor">
        <path fillRule="evenodd" d="M8 4a4 4 0 100 8 4 4 0 000-8zM2 8a6 6 0 1110.89 3.476l4.817 4.817a1 1 0 01-1.414 1.414l-4.816-4.816A6 6 0 012 8z" clipRule="evenodd" />
    </svg>
);

const CheckCircleIcon: React.FC<{ className?: string }> = ({ className }) => (
    <svg xmlns="http://www.w3.org/2000/svg" className={className} fill="none" viewBox="0 0 24 24" stroke="currentColor">
        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 12l2 2 4-4m6 2a9 9 0 11-18 0 9 9 0 0118 0z" />
    </svg>
);

const PlusIcon: React.FC<{ className?: string }> = ({ className }) => (
  <svg xmlns="http://www.w3.org/2000/svg" className={className} fill="none" viewBox="0 0 24 24" stroke="currentColor">
      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 4v16m8-8H4" />
  </svg>
);

const BOMScreen: React.FC<BOMScreenProps> = ({ 
  parts, 
  workplaces, 
  bomItems, 
  onAddTask, 
  onRequestBOM, 
  t, 
  language 
}) => {
  const [bomParentQuery, setBomParentQuery] = useState('');
  const [bomQuantity, setBomQuantity] = useState('');
  const [bomSelectedWorkplace, setBomSelectedWorkplace] = useState<string | null>(null);
  const [clickedBOMTasks, setClickedBOMTasks] = useState<Set<string>>(new Set());
  const [bomRequestStatus, setBomRequestStatus] = useState<'idle' | 'loading' | 'success'>('idle');
  const [displayedBomParent, setDisplayedBomParent] = useState<string | null>(null);
  const [displayedBomQuantity, setDisplayedBomQuantity] = useState<number | null>(null);

  const handleCalculateBOM = () => {
    if (!bomParentQuery || !bomQuantity || parseFloat(bomQuantity) <= 0) {
        alert(t('bom_invalid_input')); 
        return;
    }
    setDisplayedBomParent(bomParentQuery);
    setDisplayedBomQuantity(parseFloat(bomQuantity));
    setClickedBOMTasks(new Set());
  };

  const handleCreateBOMTask = (childPart: string, qty: number) => {
    if (!bomSelectedWorkplace) {
        alert(t('select_bom_workplace'));
        return;
    }
    onAddTask(childPart, bomSelectedWorkplace, qty.toString(), 'pcs', 'NORMAL', false);
    setClickedBOMTasks(prev => new Set(prev).add(childPart));
  };

  const handleCreateAllBOMTasks = (results: any[]) => {
      if (!bomSelectedWorkplace) {
          alert(t('select_bom_workplace'));
          return;
      }
      results.forEach(res => {
          if (!clickedBOMTasks.has(res.childPart)) {
              handleCreateBOMTask(res.childPart, res.requiredQty);
          }
      });
  };

  const handleRequestNewBOM = async () => {
      if (!bomParentQuery) return;
      setBomRequestStatus('loading');
      const success = await onRequestBOM(bomParentQuery);
      if (success) {
          setBomRequestStatus('success');
          setTimeout(() => setBomRequestStatus('idle'), 3000);
      } else {
          setBomRequestStatus('idle');
      }
  };

  const bomResults = useMemo(() => {
    if (!displayedBomParent || !displayedBomQuantity) return [];
    return bomItems
        .filter(item => item.parentPart === displayedBomParent)
        .map(item => ({
            ...item,
            requiredQty: Math.ceil(item.quantity * displayedBomQuantity)
        }));
  }, [displayedBomParent, displayedBomQuantity, bomItems]);

  return (
    <div className="h-full animate-fade-in pb-20">
        <div className="max-w-7xl mx-auto">
            <div className="grid grid-cols-1 lg:grid-cols-12 gap-8">

                <div className="lg:col-span-4 space-y-6">
                    <div className="bg-gray-800 p-8 rounded-2xl shadow-xl border border-gray-700">
                        <div className="flex items-center gap-3 mb-8">
                            <div className="p-2 bg-teal-500/20 rounded-lg">
                                <ClipboardListIcon className="w-8 h-8 text-teal-400" />
                            </div>
                            <h2 className="text-2xl font-bold text-white uppercase tracking-tight">{t('bom_title')}</h2>
                        </div>

                        <div className="space-y-6">
                            <div>
                                <label className="block text-gray-300 text-base font-bold mb-2 uppercase tracking-wide">{t('bom_parent')}</label>
                                <PartNumberInput 
                                    parts={parts.map(p => p.value)} 
                                    value={bomParentQuery} 
                                    onInputChange={(val) => setBomParentQuery(val)} 
                                    onPartSelect={(val) => { if (val) setBomParentQuery(val); }} 
                                    placeholder={t('part_placeholder')} 
                                />
                            </div>
                            <div>
                                <label className="block text-gray-300 text-base font-bold mb-2 uppercase tracking-wide">{t('bom_qty')}</label>
                                <input 
                                    type="number" 
                                    inputMode="numeric"
                                    value={bomQuantity} 
                                    onChange={(e) => setBomQuantity(e.target.value.slice(0, 7))} 
                                    maxLength={7}
                                    className="w-full h-12 px-4 bg-gray-700 border border-gray-600 rounded-lg text-white font-mono placeholder-gray-500 focus:outline-none focus:ring-2 focus:ring-teal-500 transition-all text-base uppercase" 
                                    placeholder="500" 
                                />
                            </div>
                            <div>
                                <label className="block text-gray-300 text-base font-bold mb-2 uppercase tracking-wide">{t('bom_select_wp')}</label>
                                <select 
                                    value={bomSelectedWorkplace || ''} 
                                    onChange={(e) => setBomSelectedWorkplace(e.target.value)} 
                                    className="w-full h-12 px-4 bg-gray-700 border border-gray-600 rounded-lg text-white focus:outline-none focus:ring-2 focus:ring-teal-500 transition-all font-mono uppercase text-base"
                                >
                                    <option value="" className="font-sans normal-case">{t('workplace_placeholder')}</option>
                                    {workplaces.map(wp => <option key={wp.id} value={wp.value}>{wp.value}</option>)}
                                </select>
                            </div>

                            <button 
                                onClick={handleCalculateBOM} 
                                className="w-full h-14 bg-teal-600 hover:bg-teal-500 text-white font-bold py-4 rounded-xl shadow-lg shadow-teal-900/20 transform transition-all active:scale-95 flex items-center justify-center gap-3 text-lg uppercase tracking-widest"
                            >
                                <ActivityIcon className="h-6 w-6" />
                                {t('bom_calc_btn')}
                            </button>

                            {bomParentQuery && bomResults.length === 0 && (
                                <button 
                                    onClick={handleRequestNewBOM}
                                    disabled={bomRequestStatus !== 'idle'}
                                    className={`w-full h-12 rounded-xl border text-base font-bold transition-all uppercase tracking-wide ${
                                        bomRequestStatus === 'success' ? 'bg-green-600 border-green-500 text-white' : 
                                        bomRequestStatus === 'loading' ? 'bg-gray-700 border-gray-600 text-gray-400 animate-pulse' :
                                        'bg-gray-800 border-gray-600 text-gray-300 hover:bg-gray-700'
                                    }`}
                                >
                                    {bomRequestStatus === 'loading' ? '...' : bomRequestStatus === 'success' ? t('bom_req_success') : t('bom_request_btn')}
                                </button>
                            )}
                        </div>
                    </div>

                    {bomResults.length > 0 && (
                        <div className="grid grid-cols-2 gap-4">
                            <div className="bg-gray-800 p-5 rounded-xl border border-gray-700 shadow-md">
                                <p className="text-gray-500 text-[10px] font-black uppercase tracking-[0.2em]">{language === 'sk' ? 'Komponenty' : 'Components'}</p>
                                <p className="text-3xl font-black text-white mt-1">{bomResults.length}</p>
                            </div>
                            <div className="bg-gray-800 p-5 rounded-xl border border-gray-700 shadow-md">
                                <p className="text-gray-500 text-[10px] font-black uppercase tracking-[0.2em]">{language === 'sk' ? 'Zostáva' : 'Remaining'}</p>
                                <p className="text-3xl font-black text-orange-400 mt-1">{bomResults.length - clickedBOMTasks.size}</p>
                            </div>
                        </div>
                    )}
                </div>

                <div className="lg:col-span-8">
                    {bomResults.length > 0 ? (
                        <div className="bg-gray-800 rounded-2xl shadow-xl border border-gray-700 overflow-hidden flex flex-col h-full">
                            <div className="p-6 sm:p-8 border-b border-gray-700 flex justify-between items-center bg-gray-900/40">
                                <div>
                                    <h3 className="text-2xl font-black text-white font-mono uppercase tracking-tight">
                                        {displayedBomParent}
                                    </h3>
                                    <p className="text-base text-gray-500 mt-1">
                                        {t('bom_results')} <span className="text-teal-400 font-black">{displayedBomQuantity} ks</span>
                                    </p>
                                </div>
                                <button 
                                    onClick={() => handleCreateAllBOMTasks(bomResults)}
                                    className="bg-sky-600 hover:bg-sky-500 text-white px-8 py-3.5 rounded-xl text-base font-black shadow-lg transition-all active:scale-95 flex items-center gap-3 uppercase tracking-widest border-2 border-sky-500"
                                >
                                    🚀 {language === 'sk' ? 'Odoslať Všetko' : 'Send All'}
                                </button>
                            </div>

                            <div className="overflow-x-auto flex-grow custom-scrollbar">
                                <table className="w-full text-left">
                                    <thead className="bg-gray-900/50 text-gray-500 text-[10px] font-black uppercase tracking-[0.2em] border-b border-gray-700">
                                        <tr>
                                            <th className="py-5 px-8">{t('bom_child')}</th>
                                            <th className="py-5 px-8 text-center">{language === 'sk' ? 'Spotreba/ks' : 'Usage/pc'}</th>
                                            <th className="py-5 px-8 text-right">{t('bom_req_qty')}</th>
                                            <th className="py-5 px-8 text-center">{language === 'sk' ? 'Akcia' : 'Action'}</th>
                                        </tr>
                                    </thead>
                                    <tbody className="divide-y divide-gray-700/50">
                                        {bomResults.map((res) => {
                                            const isSent = clickedBOMTasks.has(res.childPart);
                                            return (
                                                <tr key={res.childPart} className={`transition-colors ${isSent ? 'bg-teal-500/5 opacity-60' : 'hover:bg-gray-700/30'}`}>
                                                    <td className="py-6 px-8">
                                                        <p className={`font-mono font-bold text-base ${isSent ? 'text-gray-500' : 'text-white'}`}>{res.childPart}</p>
                                                        <p className="text-[10px] text-gray-500 font-bold uppercase tracking-tight">Standard Component</p>
                                                    </td>
                                                    <td className="py-6 px-8 text-center text-gray-400 font-mono text-sm">
                                                        {res.quantity}
                                                    </td>
                                                    <td className="py-6 px-8 text-right">
                                                        <span className={`text-xl font-black font-mono ${isSent ? 'text-gray-500' : 'text-teal-400'}`}>
                                                            {res.requiredQty} <span className="text-xs font-normal opacity-70">ks</span>
                                                        </span>
                                                    </td>
                                                    <td className="py-6 px-8 text-center">
                                                        <button 
                                                            onClick={() => !isSent && handleCreateBOMTask(res.childPart, res.requiredQty)}
                                                            disabled={isSent}
                                                            className={`inline-flex items-center justify-center h-14 w-14 rounded-xl transition-all shadow-lg border-2 ${
                                                                isSent ? 'bg-gray-700 text-teal-500 border-gray-600' : 'bg-teal-600/20 text-teal-400 hover:bg-teal-600 hover:text-white border-teal-500/30 active:scale-90'
                                                            }`}
                                                        >
                                                            {isSent ? <CheckCircleIcon className="w-8 h-8" /> : <PlusIcon className="w-8 h-8" />}
                                                        </button>
                                                    </td>
                                                </tr>
                                            );
                                        })}
                                    </tbody>
                                </table>
                            </div>
                        </div>
                    ) : (
                        <div className="h-full flex flex-col items-center justify-center bg-gray-800/50 rounded-2xl border-2 border-dashed border-gray-700 p-12 text-center shadow-inner">
                            <div className="w-24 h-24 bg-gray-700 rounded-full flex items-center justify-center mb-6 shadow-xl border border-gray-600">
                                <SearchIcon className="w-12 h-12 text-gray-500" />
                            </div>
                            <h3 className="text-2xl font-black text-gray-400 mb-3 uppercase tracking-tighter">{language === 'sk' ? 'Žiadne dáta na zobrazenie' : 'No data to display'}</h3>
                            <p className="text-gray-500 max-w-xs text-base font-medium leading-relaxed">{language === 'sk' ? 'Zadajte číslo výrobku a plánované množstvo pre výpočet potrebného materiálu.' : 'Enter product number and planned quantity to calculate required material.'}</p>
                        </div>
                    )}
                </div>

            </div>
        </div>
    </div>
  );
};

