  id: string;
  partNumber?: string;
  text?: string;
  workplace?: string;
  quantity?: string;
  quantityUnit?: string;
  priority: PriorityLevel;
  isDone: boolean;
  isLogistics?: boolean;
  note?: string;
  createdAt: number;
  createdBy?: string;
  startedAt?: number;
  completedAt?: number;
  completedBy?: string;
  isMissing?: boolean;
  missingReason?: string;
  missingReportedBy?: string;
  isInProgress?: boolean;
  inProgressBy?: string | null;
  isBlocked?: boolean;
  blockedBy?: string | null;
  isManualBlocked?: boolean;
  isAuditInProgress?: boolean;
  auditBy?: string | null;
  auditResult?: 'OK' | 'NOK' | null;
  auditNote?: string;
