}

export interface SystemBreak {
  id: string;
  start: number;
  end?: number;
}

export interface BOMItem {
  id: string;
  parentPart: string;
  childPart: string;
  quantity: number;
}

export interface Role {
  id: string;
  name: string;
  isSystem?: boolean;
}

export interface Permission {
  id: string;
  roleId: string;
