}

export interface Notification {
  id: string;
  partNumber: string;
  reason: string;
  reportedBy: string;
  targetUser: string;
  timestamp: number;
}

/**
 * Main Application Component
 * Manages the global state and provides shared logic for sub-components.
 */
const App: React.FC = () => {
  // Application State - In a full implementation, these would be synchronized with Firestore
  const [currentUser] = useState<string>('ADMIN'); 
  const [tasks] = useState<Task[]>([]); 

  /**
   * Finalizuje audit dielu a aktualizuje stav v databáze.
   * Minimalizuje reads tým, že pracuje s ID priamo cez Firestore doc reference.
   * Opravené zachovanie histórie nahlásenia chýbajúceho tovaru.
   */
  const handleFinishAudit = async (id: string, result: 'found' | 'missing', note: string) => {
      const t = tasks.find(x => x.id === id);
      if (!t) return;
      const statusLabel = result === 'found' ? 'OK' : 'CHÝBA';
      const badgeText = `AUDIT ${statusLabel}: ${note} (${currentUser})`;
      const auditData = { 
          auditedBy: currentUser, 
          auditedAt: Date.now(), 
          auditResult: result === 'found' ? 'OK' : 'NOK', 
          auditNote: note, 
          isAuditInProgress: false, 
          auditBy: null, 
          auditFinalBadge: badgeText 
      };

      // Implementácia batch updates by bola lepšia pre kvóty, ale tu používame updateDoc pre jednoduchosť
      if (result === 'found') {
          // OPRAVA: Už nemažeme missingReason a missingReportedBy, aby zostali v histórii
          await updateDoc(doc(db, 'tasks', id), { ...auditData, isMissing: false });
      } else {
          // Pri nahlásenom chýbajúcom tovare, ktorý sa nenašiel ani v audite, uzatvárame úlohu
          await updateDoc(doc(db, 'tasks', id), { 
              ...auditData, 
              isDone: true, 
              status: 'completed', 
              completionTime: new Date().toLocaleTimeString('sk-SK'), 
              completedBy: currentUser, 
              completedAt: Date.now() 
          });
      }

      // Odoslanie notifikácie tvorcovi úlohy o výsledku auditu
      if (t.createdBy && t.createdBy !== currentUser) {
          await addDoc(collection(db, 'notifications'), { 
              partNumber: t.partNumber || 'N/A', 
              reason: `AUDIT DOKONČENÝ (${statusLabel}): ${note}`, 
              reportedBy: currentUser, 
              targetUser: t.createdBy, 
              timestamp: Date.now() 
          });
      }
  };

  // Dummy reference for development view
  console.log('App logic ready. handleFinishAudit bound.');

  return (
    <div className="min-h-screen bg-slate-900 text-slate-200 flex flex-col items-center justify-center p-4">
      <header className="text-center space-y-4">
        <h1 className="text-5xl font-black text-teal-400 tracking-tighter uppercase italic drop-shadow-lg">
          Clamason Task Manager
        </h1>
        <p className="text-slate-500 font-mono text-sm uppercase tracking-[0.3em]">
          Automotive Logistics & Warehouse Management
        </p>
      </header>

      <main className="mt-12 bg-slate-800/50 p-8 rounded-3xl border border-slate-700 shadow-2xl backdrop-blur-sm max-w-md w-full text-center">
        <p className="text-slate-400 text-sm mb-6">Systém je inicializovaný a pripravený na prácu.</p>
        <div className="space-y-3">
          <div className="bg-teal-500/10 text-teal-400 p-4 rounded-xl border border-teal-500/20 font-bold uppercase text-xs">
            Offline Persistence Active
          </div>
          <div className="bg-blue-500/10 text-blue-400 p-4 rounded-xl border border-blue-500/20 font-bold uppercase text-xs">
            Multi-tab Sync Enabled
          </div>
        </div>
      </main>

      <footer className="mt-12 text-slate-600 text-[10px] font-black uppercase tracking-widest">
        © 2025 Industrial Task Manager | Build v1.0.4
      </footer>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useRef } from 'react';
import LoginScreen from './components/LoginScreen';
import PartSearchScreen from './components/PartSearchScreen';
import { db } from './firebase';
import { 
  collection, 
  onSnapshot, 
  addDoc, 
  updateDoc, 
  deleteDoc, 
  doc, 
  query, 
  orderBy,
  writeBatch,
  getDocs,
  where,
  limit,
  setDoc,
  increment 
} from 'firebase/firestore';

